    conds.append(f"citation LIKE '%\"publication_number\": \\\"{p}\\\"%'")

# Return for downstream querying: list of conditions and uc_df mapping
out = {
    'uc_pubs': uc_pubs,
    'like_conds': conds,
    'uc_primary_map': uc_df.to_dict(orient='records')
}
print('__RESULT__:')
print(json.dumps(out))

